import * as React from "react"
import { graphql } from "gatsby"

import Layout from "../../components/layout"
import Seo from "../../components/seo"

const ColorTheoryIndex = ({ data, location }) => {
    const siteTitle = data.site.siteMetadata?.title || `Title`

    // States for intermediate section
    const [h, setH] = React.useState(180)
    const [s, setS] = React.useState(50)
    const [v, setV] = React.useState(80)

    const colorWheelRef = React.useRef(null)
    const rgbChartRef = React.useRef(null)
    const chartInstance = React.useRef(null)

    // Advanced section state
    const [isIllusionActive, setIsIllusionActive] = React.useState(true)

    // Helper
    const hsvToRgb = (h, s, v) => {
        s = s / 100;
        v = v / 100;
        let c = v * s;
        let x = c * (1 - Math.abs((h / 60) % 2 - 1));
        let m = v - c;
        let r = 0, g = 0, b = 0;

        if (0 <= h && h < 60) { r = c; g = x; b = 0; }
        else if (60 <= h && h < 120) { r = x; g = c; b = 0; }
        else if (120 <= h && h < 180) { r = 0; g = c; b = x; }
        else if (180 <= h && h < 240) { r = 0; g = x; b = c; }
        else if (240 <= h && h < 300) { r = x; g = 0; b = c; }
        else if (300 <= h && h <= 360) { r = c; g = 0; b = x; }

        return [
            Math.round((r + m) * 255),
            Math.round((g + m) * 255),
            Math.round((b + m) * 255)
        ];
    }

    const rgb = React.useMemo(() => hsvToRgb(h, s, v), [h, s, v])
    const rgbString = `rgb(${rgb[0]}, ${rgb[1]}, ${rgb[2]})`
    const hex = "#" + (1 << 24 | rgb[0] << 16 | rgb[1] << 8 | rgb[2]).toString(16).slice(1).toUpperCase()

    React.useEffect(() => {
        // Draw color wheel
        if (colorWheelRef.current) {
            const canvas = colorWheelRef.current;
            const ctx = canvas.getContext('2d');
            const radius = canvas.width / 2;

            ctx.clearRect(0, 0, canvas.width, canvas.height); // clear for good measure

            for (let angle = 0; angle < 360; angle++) {
                ctx.beginPath();
                ctx.moveTo(radius, radius);
                ctx.arc(radius, radius, radius, (angle - 90) * Math.PI / 180, (angle - 88) * Math.PI / 180);
                ctx.closePath();
                ctx.fillStyle = `hsl(${angle}, 100%, 50%)`;
                ctx.fill();
            }

            ctx.beginPath();
            ctx.arc(radius, radius, radius * 0.3, 0, 2 * Math.PI);
            ctx.fillStyle = '#ffffff';
            ctx.fill();
        }
    }, [])

    React.useEffect(() => {
        // Wait for window.Chart or use an interval
        let chartCheckInterval = setInterval(() => {
            if (window.Chart && rgbChartRef.current) {
                clearInterval(chartCheckInterval)
                if (!chartInstance.current) {
                    const chartCtx = rgbChartRef.current.getContext('2d');
                    chartInstance.current = new window.Chart(chartCtx, {
                        type: 'bar',
                        data: {
                            labels: ['Red', 'Green', 'Blue'],
                            datasets: [{
                                label: 'Intensity (0-255)',
                                data: rgb,
                                backgroundColor: ['#ef4444', '#22c55e', '#3b82f6'],
                                borderWidth: 0,
                                borderRadius: 4
                            }]
                        },
                        options: {
                            responsive: true,
                            maintainAspectRatio: false,
                            scales: {
                                y: {
                                    beginAtZero: true,
                                    max: 255,
                                    grid: { color: '#e5e7eb' }
                                },
                                x: {
                                    grid: { display: false }
                                }
                            },
                            plugins: {
                                legend: { display: false }
                            }
                        }
                    });
                }
            }
        }, 100);

        return () => {
            clearInterval(chartCheckInterval);
            if (chartInstance.current) {
                chartInstance.current.destroy();
                chartInstance.current = null;
            }
        }
    }, [])

    React.useEffect(() => {
        if (chartInstance.current) {
            chartInstance.current.data.datasets[0].data = rgb;
            chartInstance.current.update();
        }
    }, [rgb])

    return (
        <Layout location={location} title={siteTitle}>
            <style>{`
                html { scroll-behavior: smooth; }
                .chart-container { position: relative; width: 100%; max-width: 600px; margin-left: auto; margin-right: auto; height: 350px; max-height: 400px; }
                input[type=range] { -webkit-appearance: none; width: 100%; background: transparent; }
                input[type=range]::-webkit-slider-thumb { -webkit-appearance: none; height: 20px; width: 20px; border-radius: 50%; background: #444; cursor: pointer; margin-top: -8px; }
                input[type=range]::-webkit-slider-runnable-track { width: 100%; height: 4px; cursor: pointer; background: #ddd; border-radius: 2px; }
            `}</style>
            <div className="bg-stone-50 text-stone-800 antialiased selection:bg-stone-300 selection:text-stone-900" style={{ fontFamily: "'Inter', sans-serif" }}>
                <nav className="fixed top-0 w-full bg-stone-100/90 backdrop-blur-md border-b border-stone-200 z-50">
                    <div className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8">
                        <div className="flex justify-between items-center h-16">
                            <div className="flex-shrink-0 font-bold text-xl tracking-tight text-stone-900">Color Theory</div>
                            <div className="hidden md:flex space-x-8">
                                <a href="#beginner" className="text-stone-600 hover:text-stone-900 transition-colors font-medium">Beginner</a>
                                <a href="#intermediate" className="text-stone-600 hover:text-stone-900 transition-colors font-medium">Intermediate</a>
                                <a href="#advanced" className="text-stone-600 hover:text-stone-900 transition-colors font-medium">Advanced</a>
                            </div>
                        </div>
                    </div>
                </nav>

                <header className="pt-32 pb-20 px-4 sm:px-6 lg:px-8 max-w-4xl mx-auto text-center">
                    <h1 className="text-5xl md:text-6xl font-extrabold tracking-tight text-stone-900 mb-6">The Interaction of Color</h1>
                    <p className="text-xl text-stone-600 leading-relaxed mb-10">A journey from the fundamental physics of light to the psychological illusions of human perception. Inspired by the teachings of Josef Albers, explore how colors behave, interact, and deceive.</p>
                    <a href="#beginner" className="inline-flex items-center justify-center px-8 py-3 border border-transparent text-base font-medium rounded-md text-white bg-stone-800 hover:bg-stone-700 transition-colors">Start the Journey &darr;</a>
                </header>

                <main className="max-w-6xl mx-auto px-4 sm:px-6 lg:px-8 pb-32">
                    <section id="beginner" className="mb-32 scroll-mt-24">
                        <div className="mb-12 border-b border-stone-200 pb-8">
                            <span className="text-sm font-bold uppercase tracking-widest text-stone-500">Phase 01</span>
                            <h2 className="text-4xl font-bold mt-2 mb-4 text-stone-900">Beginner: The Foundations</h2>
                            <p className="text-lg text-stone-600 max-w-3xl">Before we can manipulate color, we must organize it. The color wheel is the most basic tool for understanding how human vision categorizes the spectrum of light. This section introduces the core vocabulary needed to communicate visual ideas.</p>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-12 items-center">
                            <div className="bg-white p-8 rounded-2xl shadow-sm border border-stone-100 flex flex-col items-center justify-center">
                                <canvas ref={colorWheelRef} width="300" height="300" className="max-w-full h-auto rounded-full shadow-inner"></canvas>
                                <p className="mt-6 text-sm text-stone-500 font-medium">Continuous HSL Spectrum</p>
                            </div>
                            <div>
                                <h3 className="text-2xl font-bold mb-4 text-stone-800">The Anatomy of the Wheel</h3>
                                <p className="text-stone-600 mb-6 leading-relaxed">The standard color wheel maps the visible spectrum into a circle. By arranging colors this way, we can immediately see relationships and categories.</p>

                                <div className="space-y-6">
                                    <div>
                                        <h4 className="font-bold text-stone-900 flex items-center gap-2">
                                            <span className="w-3 h-3 rounded-full bg-red-500"></span>
                                            Primary Colors
                                        </h4>
                                        <p className="text-stone-600 text-sm mt-1">Red, Yellow, and Blue. In traditional art theory, these are the base pigments that cannot be created by mixing other colors.</p>
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-stone-900 flex items-center gap-2">
                                            <span className="w-3 h-3 rounded-full bg-green-500"></span>
                                            Secondary Colors
                                        </h4>
                                        <p className="text-stone-600 text-sm mt-1">Green, Orange, and Purple. Formed by mixing equal parts of two primary colors.</p>
                                    </div>
                                    <div>
                                        <h4 className="font-bold text-stone-900 flex items-center gap-2">
                                            <span className="w-3 h-3 rounded-full" style={{ background: 'linear-gradient(to right, #ef4444, #3b82f6)' }}></span>
                                            Temperature
                                        </h4>
                                        <p className="text-stone-600 text-sm mt-1">The wheel can be split in half: Warm colors (Reds, Oranges, Yellows) advance towards the viewer, while Cool colors (Blues, Greens) recede into the background.</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </section>

                    <section id="intermediate" className="mb-32 scroll-mt-24">
                        <div className="mb-12 border-b border-stone-200 pb-8">
                            <span className="text-sm font-bold uppercase tracking-widest text-stone-500">Phase 02</span>
                            <h2 className="text-4xl font-bold mt-2 mb-4 text-stone-900">Intermediate: Dimensions of Color</h2>
                            <p className="text-lg text-stone-600 max-w-3xl">Color is three-dimensional. While the color wheel shows us 'Hue', it misses 'Saturation' and 'Value'. By adjusting these three parameters (HSV), we can create millions of distinct colors. Use the laboratory below to dissect exactly how a digital color is built.</p>
                        </div>

                        <div className="bg-white rounded-3xl p-6 md:p-10 shadow-lg border border-stone-200">
                            <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">

                                <div className="space-y-8 flex flex-col justify-center">
                                    <div>
                                        <div className="flex justify-between mb-2">
                                            <label className="font-bold text-stone-800 text-sm">Hue (Color Family)</label>
                                            <span className="text-sm font-mono text-stone-500">{h}&deg;</span>
                                        </div>
                                        <input type="range" min="0" max="360" value={h} onChange={e => setH(parseInt(e.target.value))} />
                                        <div className="h-2 w-full mt-2 rounded" style={{ background: 'linear-gradient(to right, #f00 0%, #ff0 17%, #0f0 33%, #0ff 50%, #00f 67%, #f0f 83%, #f00 100%)' }}></div>
                                    </div>

                                    <div>
                                        <div className="flex justify-between mb-2">
                                            <label className="font-bold text-stone-800 text-sm">Saturation (Intensity)</label>
                                            <span className="text-sm font-mono text-stone-500">{s}%</span>
                                        </div>
                                        <input type="range" min="0" max="100" value={s} onChange={e => setS(parseInt(e.target.value))} />
                                        <div className="h-2 w-full mt-2 rounded" style={{ background: 'linear-gradient(to right, #888, #0ff)' }}></div>
                                    </div>

                                    <div>
                                        <div className="flex justify-between mb-2">
                                            <label className="font-bold text-stone-800 text-sm">Value (Lightness)</label>
                                            <span className="text-sm font-mono text-stone-500">{v}%</span>
                                        </div>
                                        <input type="range" min="0" max="100" value={v} onChange={e => setV(parseInt(e.target.value))} />
                                        <div className="h-2 w-full mt-2 rounded" style={{ background: 'linear-gradient(to right, #000, #fff)' }}></div>
                                    </div>
                                </div>

                                <div className="flex flex-col items-center justify-center">
                                    <div className="w-full h-48 md:h-64 rounded-2xl shadow-inner transition-colors duration-75" style={{ backgroundColor: rgbString }}></div>
                                    <div className="mt-6 font-mono text-lg font-bold text-stone-800 tracking-wider">{hex}</div>
                                </div>

                                <div className="flex flex-col justify-center w-full">
                                    <h4 className="text-center font-bold text-stone-800 mb-4 text-sm uppercase tracking-wide">RGB Data Output</h4>
                                    <div className="chart-container w-full">
                                        <canvas ref={rgbChartRef}></canvas>
                                    </div>
                                </div>

                            </div>
                        </div>
                    </section>

                    <section id="advanced" className="mb-20 scroll-mt-24">
                        <div className="mb-12 border-b border-stone-200 pb-8">
                            <span className="text-sm font-bold uppercase tracking-widest text-stone-500">Phase 03</span>
                            <h2 className="text-4xl font-bold mt-2 mb-4 text-stone-900">Advanced: The Relativity of Color</h2>
                            <p className="text-lg text-stone-600 max-w-3xl">Josef Albers famously stated: <em>"In visual perception a color is almost never seen as it really is—as it physically is. This fact makes color the most relative medium in art."</em> This section demonstrates Simultaneous Contrast, where a single color appears as two completely different colors based on its surroundings.</p>
                        </div>

                        <div className="bg-stone-900 rounded-3xl p-6 md:p-12 shadow-2xl overflow-hidden">
                            <div className="text-center mb-10 text-stone-100">
                                <h3 className="text-3xl font-light mb-4">The Albers Illusion</h3>
                                <p className="text-stone-400 max-w-2xl mx-auto">Look at the two small center squares. To the human eye, the left square appears to be a light, warm brown, while the right square appears to be a darker, cooler gray. In reality, they are exactly the same physical color.</p>
                            </div>

                            <div className="flex flex-col md:flex-row w-full h-80 rounded-xl overflow-hidden shadow-inner relative group">
                                <div className="flex-1 flex items-center justify-center transition-colors duration-700 ease-in-out" style={{ backgroundColor: isIllusionActive ? '#1e3a8a' : '#ffffff' }}>
                                    <div className="w-24 h-24 shadow-lg transition-transform duration-500 group-hover:scale-110" style={{ backgroundColor: '#8b7d6b' }}></div>
                                </div>

                                <div className="flex-1 flex items-center justify-center transition-colors duration-700 ease-in-out" style={{ backgroundColor: isIllusionActive ? '#fef08a' : '#ffffff' }}>
                                    <div className="w-24 h-24 shadow-lg transition-transform duration-500 group-hover:scale-110" style={{ backgroundColor: '#8b7d6b' }}></div>
                                </div>
                            </div>

                            <div className="mt-10 flex justify-center">
                                <button onClick={() => setIsIllusionActive(!isIllusionActive)} className="px-8 py-4 bg-white text-stone-900 font-bold rounded-full shadow-lg hover:scale-105 transition-transform">
                                    {isIllusionActive ? 'Remove Backgrounds to Reveal Truth' : 'Restore Background Context'}
                                </button>
                            </div>
                        </div>
                    </section>

                </main>

                <footer className="bg-stone-900 text-stone-400 py-12 text-center text-sm">
                    <p>Created for educational exploration of Color Theory.</p>
                </footer>
            </div>
        </Layout>
    )
}

export default ColorTheoryIndex

export const Head = () => (
    <>
        <Seo title="Interaction of Color: A Digital Exploration" />
        <script src="https://cdn.tailwindcss.com"></script>
        <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    </>
)

export const pageQuery = graphql`
  {
    site {
      siteMetadata {
        title
      }
    }
    allMarkdownRemark(sort: { frontmatter: { date: DESC } }) {
      nodes {
        excerpt
        fields {
          slug
        }
        frontmatter {
          date(formatString: "MMMM DD, YYYY")
          title
          description
        }
      }
    }
  }
`
